parameters.text:
=You are an expert tutor. I am providing you with the exact extracted text from my textbook.

TEXT CONTENT: {{ $json.text }}


Requirements:
- Number of questions: {{ $('Get-Details').item.json['Number of Questions'] }}
- Difficulty level: {{ $('Get-Details').item.json.Difficulty }}

Return ONLY a valid JSON array in this exact format:
[{"q": "Question text?", "options": {"A": "...", "B": "...", "C": "...", "D": "..."}, "answer": "A", "explanation": "..."}]

CRITICAL INSTRUCTION: You must return ONLY valid, perfectly formatted JSON. Do not include any trailing commas, missing brackets, or extra text outside the JSON structure. If the JSON is invalid, the system will crash.

parameters.jsCode:
// 1. Get the AI's output and clean the markdown backticks
const aiResponse = $input.item.json.text;
const cleanJson = aiResponse.replace(/```json/g, '').replace(/```/g, '').trim();

// 2. Parse the string into an actual JavaScript array
let mcqs;
try {
    mcqs = JSON.parse(cleanJson);
} catch (e) {
    mcqs = [{"q": "Error loading questions", "options": {"A":"-","B":"-","C":"-","D":"-"}, "answer": "A", "explanation": "Failed to parse AI output."}];
}

// 3. Get the student's name from the trigger node
const name = $('On form submission').first().json["Name"] || "Student";

// 4. Build the HTML template with Interactive JavaScript
let htmlContent = `
<html>
<head>
    <meta charset="utf-8">
    <style>
        body { font-family: Arial, sans-serif; padding: 40px; line-height: 1.6; color: #333; max-width: 800px; margin: auto; }
        .header { text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; margin-bottom: 30px; }
        .card { border: 1px solid #e0e0e0; padding: 20px; margin-bottom: 20px; border-radius: 8px; background-color: #fcfcfc; }
        .question { font-weight: bold; font-size: 1.1em; color: #2c3e50; margin-bottom: 15px; }
        .options { margin-left: 10px; margin-bottom: 15px; }

        /* Make the radio buttons look like clickable rows */
        .option-label { display: block; margin-bottom: 8px; cursor: pointer; padding: 8px; border-radius: 4px; transition: 0.2s; }
        .option-label:hover { background-color: #f0f0f0; }

        /* The answer box is hidden by default */
        .answer-box { padding: 15px; border-radius: 4px; margin-top: 15px; display: none; }

        /* Dynamic colors injected by JavaScript */
        .correct-box { background-color: #e8f5e9; border-left: 4px solid #4caf50; }
        .incorrect-box { background-color: #ffebee; border-left: 4px solid #f44336; }

        .answer { font-weight: bold; margin-bottom: 5px; font-size: 1.1em; }
        .explanation { color: #555; font-size: 0.95em; margin-top: 10px; }
    </style>

    <script>
        // This function runs when a user clicks a radio button
        function checkAnswer(qIndex, selected, correct) {
            const box = document.getElementById('answer-box-' + qIndex);
            const answerText = document.getElementById('answer-text-' + qIndex);

            // Show the answer box
            box.style.display = 'block';

            // Check if they got it right or wrong
            if(selected === correct) {
                box.className = 'answer-box correct-box';
                answerText.innerHTML = '✅ Correct! The answer is ' + correct;
                answerText.style.color = '#2e7d32';
            } else {
                box.className = 'answer-box incorrect-box';
                answerText.innerHTML = '❌ Incorrect. The correct answer is ' + correct;
                answerText.style.color = '#c62828';
            }

            // Disable all radio buttons for this question so they can't change their answer
            const radios = document.getElementsByName('q' + qIndex);
            for(let i=0; i < radios.length; i++) {
                radios[i].disabled = true;
            }
        }
    </script>
</head>
<body>
    <div class="header">
        <h1>Data Communication Quiz</h1>
        <p>Prepared for: ${name}</p>
    </div>
`;

// Loop through each question to generate the interactive cards
mcqs.forEach((item, index) => {
    // We pass the index, the user's choice, and the actual correct answer to the JavaScript function
    htmlContent += `
    <div class="card">
        <div class="question">${index + 1}. ${item.q}</div>
        <div class="options">
            <label class="option-label">
                <input type="radio" name="q${index}" value="A" onclick="checkAnswer(${index}, 'A', '${item.answer}')"> A) ${item.options.A}
            </label>
            <label class="option-label">
                <input type="radio" name="q${index}" value="B" onclick="checkAnswer(${index}, 'B', '${item.answer}')"> B) ${item.options.B}
            </label>
            <label class="option-label">
                <input type="radio" name="q${index}" value="C" onclick="checkAnswer(${index}, 'C', '${item.answer}')"> C) ${item.options.C}
            </label>
            <label class="option-label">
                <input type="radio" name="q${index}" value="D" onclick="checkAnswer(${index}, 'D', '${item.answer}')"> D) ${item.options.D}
            </label>
        </div>

        <!-- This box stays hidden until the JavaScript tells it to appear -->
        <div id="answer-box-${index}" class="answer-box">
            <div id="answer-text-${index}" class="answer"></div>
            <div class="explanation"><strong>Explanation:</strong> ${item.explanation}</div>
        </div>
    </div>`;
});

htmlContent += `</body></html>`;

// 5. Convert the HTML string into an actual file in n8n's memory
return {
    json: { success: true },
    binary: {
        data: await this.helpers.prepareBinaryData(Buffer.from(htmlContent), "Interactive_Quiz.html", "text/html")
    }
};
